import React from "react";
import "./Header.css";

const Header = () => {
  const openNav = () => {
    document.getElementById("myNav").style.width = "100%";
  };

  const closeNav = () => {
    document.getElementById("myNav").style.width = "0%";
  };

  const scrollToSection = (sectionId) => {
    const section = document.getElementById(sectionId);
    if (section) {
      window.scrollTo({
        top: section.offsetTop,
        behavior: "smooth",
      });
    }
  };

  return (
    <header>
      <div style={{ display: "relative" }}>
        <span
          style={{
            fontSize: "30px",
            cursor: "pointer",
            display: "inline-block",
            position: "sticky",
            position: "-webkit-sticky",
            left: "10px",
            top: "10px",
          }}
          onClick={openNav}
        >
          &#9776;
        </span>
      </div>
      <div id="myNav" className="overlay">
        <a className="closebtn" onClick={closeNav}>
          &times;
        </a>
        <div className="overlay-content">
          <button className="NavButton" onClick={() => scrollToSection("home")}>
            Home
          </button>
          <a href="#">Services</a>
          <a href="#">Clients</a>
          <a href="#">Contact</a>
        </div>
      </div>
      {/* <nav>
        <ul>
          <li>
            <button
              className="NavButton"
              onClick={() => scrollToSection("home")}
            >
              Home
            </button>
          </li>
          <li>
            <button
              className="NavButton"
              onClick={() => scrollToSection("about")}
            >
              About Me
            </button>
          </li>
          <li>
            <button
              className="NavButton"
              onClick={() => scrollToSection("projects")}
            >
              My Projects
            </button>
          </li>
          <li>
            <button
              className="NavButton"
              onClick={() => scrollToSection("skills")}
            >
              Skills
            </button>
          </li>
          <li>
            <button
              className="NavButton"
              onClick={() => scrollToSection("contact")}
            >
              Contact Me
            </button>
          </li>
        </ul>
      </nav> */}
    </header>
  );
};

export default Header;
